import{_ as o}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as c,c as p,a as n,b as a,d as e,e as t}from"./app-4ed6ab18.js";const l={},r=n("h2",{id:"devcontainer란-무엇인가",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#devcontainer란-무엇인가","aria-hidden":"true"},"#"),a(" DevContainer란 무엇인가?")],-1),d={href:"https://ssowonny.medium.com/vs-code%EB%A1%9C-%EC%BB%A8%ED%85%8C%EC%9D%B4%EB%84%88-%EC%95%88%EC%97%90%EC%84%9C-%EA%B0%9C%EB%B0%9C%ED%95%98%EA%B8%B0-d8ed0950d69a",target:"_blank",rel:"noopener noreferrer"},u={href:"https://code.visualstudio.com/docs/devcontainers/containers",target:"_blank",rel:"noopener noreferrer"},m=t('<p>DevContainer는 주로 Visual Studio Code와 같은 통합 개발 환경(IDE)에서 사용되며,<br> Visual Studio Code의 확장 앱을 통해 구성할 수 있습니다.<br> 이를 통해 프로젝트를 개발하는 동안 개발 환경을 컨테이너 내에서 실행하고 호스트 시스템과 분리시키는 것이 가능합니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/5752ba51-596b-4cde-a572-ec0e39f8e8ed" alt="VSCode DevContainer 확장 앱" tabindex="0" loading="lazy"><figcaption>VSCode DevContainer 확장 앱</figcaption></figure><p>DevContainer를 설정하려면 프로젝트 루트 디렉토리에 <code>.devcontainer</code> 디렉토리를 만들고,<br> 그 안에 Dockerfile 및 환경 설정 파일을 구성해야 합니다.</p><h2 id="왜-devcontainer인가" tabindex="-1"><a class="header-anchor" href="#왜-devcontainer인가" aria-hidden="true">#</a> 왜 DevContainer인가?</h2><p>DevContainer를 사용하려고 생각한 이유는 <code>docker compose up</code> 명령으로 도커 환경 실행 시<br> vscode (IDE)에서 디버깅을 할 수 있는 방법이 없었습니다.<br> 그래서 방법이 없을까 검색을 해보던 중에 vscode내에서 도커를 사용하고 개발 환경을 적용해보기 위해 DevContainer를 사용하게 되었습니다.</p><h2 id="설정-과정" tabindex="-1"><a class="header-anchor" href="#설정-과정" aria-hidden="true">#</a> 설정 과정</h2>',6),v={href:"https://code.visualstudio.com/docs/devcontainers/create-dev-container",target:"_blank",rel:"noopener noreferrer"},b=t(`<p>저는 이미 프로젝트를 생성하고 docker-compose.yml이 설정되어 있어서<br> 이미 설정된 프로젝트를 기준으로 DevContainer를 만들어 보겠습니다.</p><p><strong>미리 설정되어 있는 루트 디렉터리의 docker-compose.yml</strong></p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">version</span><span class="token punctuation">:</span> <span class="token string">&quot;3.9&quot;</span>

<span class="token key atrule">services</span><span class="token punctuation">:</span>
  <span class="token key atrule">nest-app</span><span class="token punctuation">:</span>
    <span class="token key atrule">container_name</span><span class="token punctuation">:</span> dumpin<span class="token punctuation">-</span>admin<span class="token punctuation">-</span>NestJS
    <span class="token key atrule">build</span><span class="token punctuation">:</span>
      <span class="token key atrule">context</span><span class="token punctuation">:</span> .
      <span class="token key atrule">dockerfile</span><span class="token punctuation">:</span> docker/local.Dockerfile
    <span class="token key atrule">ports</span><span class="token punctuation">:</span>
      <span class="token comment"># app port</span>
      <span class="token punctuation">-</span> <span class="token string">&quot;3000:3000&quot;</span>
      <span class="token comment"># debugging port</span>
      <span class="token punctuation">-</span> <span class="token string">&quot;9229:9229&quot;</span>
    <span class="token key atrule">volumes</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> ./<span class="token punctuation">:</span>/usr/src/app
      <span class="token punctuation">-</span> /usr/src/app/node_modules
    <span class="token comment"># npm run start</span>
    <span class="token comment"># npm run start:debug -&gt; this is debugging mode</span>
    <span class="token key atrule">command</span><span class="token punctuation">:</span> npm run start
    <span class="token comment"># depends_on:</span>
    <span class="token comment">#   - database</span>
    <span class="token comment"># networks:</span>
    <span class="token comment">#   - mynetwork</span>
    <span class="token key atrule">environment</span><span class="token punctuation">:</span>
      <span class="token punctuation">-</span> DATABASE_NAME
      <span class="token punctuation">-</span> DATABASE_USER
      <span class="token punctuation">-</span> DATABASE_PASS
      <span class="token punctuation">-</span> DATABASE_HOST
      <span class="token punctuation">-</span> DATABASE_URL
      <span class="token punctuation">-</span> ALLOWED_ORIGINS
      <span class="token punctuation">-</span> DATABASE_PORT
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-vsode에서-devcontainer-확장앱-설치" tabindex="-1"><a class="header-anchor" href="#_1-vsode에서-devcontainer-확장앱-설치" aria-hidden="true">#</a> 1. vsode에서 DevContainer 확장앱 설치</h3><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/5752ba51-596b-4cde-a572-ec0e39f8e8ed" alt="VSCode DevContainer 확장 앱" tabindex="0" loading="lazy"><figcaption>VSCode DevContainer 확장 앱</figcaption></figure><h3 id="_2-개발-컨테이너-구성파일-만들기" tabindex="-1"><a class="header-anchor" href="#_2-개발-컨테이너-구성파일-만들기" aria-hidden="true">#</a> 2. 개발 컨테이너 구성파일 만들기</h3><p><code>F1</code>을 누르고 vscode의 명령팔레트에서 &#39;개발 컨테이너 구성파일 추가&#39;를 시작합니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/3fe0b87b-0e79-4561-9449-6098b40a4ea9" alt="개발 컨테이너 구성파일 추가" tabindex="0" loading="lazy"><figcaption>개발 컨테이너 구성파일 추가</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/2d6756de-507f-4a02-bf82-c8f611221f2f" alt="이미 docker-compose.yml이 있다면 확장앱에서 알아서 설정파일을 생성합니다" tabindex="0" loading="lazy"><figcaption>이미 docker-compose.yml이 있다면 확장앱에서 알아서 설정파일을 생성합니다</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/2fd24bd5-5e79-48fb-9a0f-adfe86ff0eb7" alt="NestJS 컨테이너를 선택했습니다" tabindex="0" loading="lazy"><figcaption>NestJS 컨테이너를 선택했습니다</figcaption></figure><p>설정이 완료되면 <code>.devcontainer</code> 폴더가 생성되고 하위에 아래와 같은 파일이 생성됩니다.</p><p><strong>.devcontainer/devcontainer.json</strong></p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Existing Docker Compose (Extend)&quot;</span><span class="token punctuation">,</span>

  <span class="token comment">// Update the &#39;dockerComposeFile&#39; list if you have more compose files or use different names.</span>
  <span class="token comment">// The .devcontainer/docker-compose.yml file contains any overrides you need/want to make.</span>
  <span class="token property">&quot;dockerComposeFile&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;../docker-compose.yml&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;docker-compose.yml&quot;</span><span class="token punctuation">]</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>.devcontainer/docker-compose.yml</strong></p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">version</span><span class="token punctuation">:</span> <span class="token string">&quot;3.9&quot;</span>
<span class="token key atrule">services</span><span class="token punctuation">:</span>
  <span class="token comment"># Update this to the name of the service you want to work with in your docker-compose.yml file</span>
  <span class="token key atrule">nest-app</span><span class="token punctuation">:</span>
    <span class="token comment"># Uncomment if you want to override the service&#39;s Dockerfile to one in the .devcontainer</span>
    <span class="token comment"># folder. Note that the path of the Dockerfile and context is relative to the *primary*</span>
    <span class="token comment"># docker-compose.yml file (the first in the devcontainer.json &quot;dockerComposeFile&quot;</span>
    <span class="token comment"># array). The sample below assumes your primary file is in the root of your project.</span>
    <span class="token comment">#</span>
    <span class="token comment"># build:</span>
    <span class="token comment">#   context: .</span>
    <span class="token comment">#   dockerfile: .devcontainer/Dockerfile</span>

    <span class="token key atrule">volumes</span><span class="token punctuation">:</span>
      <span class="token comment"># Update this to wherever you want VS Code to mount the folder of your project</span>
      <span class="token punctuation">-</span> ..<span class="token punctuation">:</span>/workspaces<span class="token punctuation">:</span>cached

    <span class="token comment"># Uncomment the next four lines if you will use a ptrace-based debugger like C++, Go, and Rust.</span>
    <span class="token comment"># cap_add:</span>
    <span class="token comment">#   - SYS_PTRACE</span>
    <span class="token comment"># security_opt:</span>
    <span class="token comment">#   - seccomp:unconfined</span>

    <span class="token comment"># Overrides default command so things don&#39;t shut down after the process ends.</span>
    <span class="token key atrule">command</span><span class="token punctuation">:</span> /bin/sh <span class="token punctuation">-</span>c &quot;while sleep 1000; do <span class="token punctuation">:</span>; done&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-컨테이너-환경-실행하고-리눅스-터미널-사용하기" tabindex="-1"><a class="header-anchor" href="#_3-컨테이너-환경-실행하고-리눅스-터미널-사용하기" aria-hidden="true">#</a> 3. 컨테이너 환경 실행하고 리눅스 터미널 사용하기</h3><p>설정파일이 생성되었다면 다시 <code>F1</code>을 누르고 명령 팔레트로 들어가서 &#39;컨테이너에서 다시 빌드하고 다시 열기&#39;를 선택합니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/c526d910-a923-4987-a2d5-38d1b2376d51" alt="컨테이너에서 다시 빌드하고 다시 열기" tabindex="0" loading="lazy"><figcaption>컨테이너에서 다시 빌드하고 다시 열기</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/48443c1f-6e06-4fd1-9c7f-a989bcd509ca" alt="원격 탐색기에 컨테이너가 생성된 모습" tabindex="0" loading="lazy"><figcaption>원격 탐색기에 컨테이너가 생성된 모습</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/2db5140c-f1d4-4c30-b734-67e20ea36e94" alt="왼쪽 아래 원격연결이 되었는지 뜹니다. 터미널도 컨테이너의 리눅스 환경으로 실행" tabindex="0" loading="lazy"><figcaption>왼쪽 아래 원격연결이 되었는지 뜹니다. 터미널도 컨테이너의 리눅스 환경으로 실행</figcaption></figure><h3 id="_4-디버깅-설정하기" tabindex="-1"><a class="header-anchor" href="#_4-디버깅-설정하기" aria-hidden="true">#</a> 4. 디버깅 설정하기</h3><p>왼쪽 사이드바 실행 및 디버그에서 <code>launch.json</code> 파일 만들기를 선택하고 Node.js를 선택합니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/fc3de268-94a3-4b87-8c14-59e2ae000511" alt="실행 및 디버그에서 launch.json 만들기" tabindex="0" loading="lazy"><figcaption>실행 및 디버그에서 launch.json 만들기</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/25a848e3-94fb-4fff-bd9c-c66f0d9d605b" alt="Node.js를 선택" tabindex="0" loading="lazy"><figcaption>Node.js를 선택</figcaption></figure><p><code>.vscode/launch.json</code>이 만들어지면 다음과 같이 디버깅 설정을 합니다.</p><div class="language-json line-numbers-mode" data-ext="json"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token comment">// IntelliSense를 사용하여 가능한 특성에 대해 알아보세요.</span>
  <span class="token comment">// 기존 특성에 대한 설명을 보려면 가리킵니다.</span>
  <span class="token comment">// 자세한 내용을 보려면 https://go.microsoft.com/fwlink/?linkid=830387을(를) 방문하세요.</span>
  <span class="token property">&quot;version&quot;</span><span class="token operator">:</span> <span class="token string">&quot;0.2.0&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;configurations&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span>
    <span class="token punctuation">{</span>
      <span class="token property">&quot;type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;node&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;request&quot;</span><span class="token operator">:</span> <span class="token string">&quot;attach&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;디버그: 프로그램 시작&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;skipFiles&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span><span class="token string">&quot;&lt;node_internals&gt;/**&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span>
      <span class="token property">&quot;port&quot;</span><span class="token operator">:</span> <span class="token number">9229</span><span class="token punctuation">,</span>
      <span class="token property">&quot;restart&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">]</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_5-디버깅-하기" tabindex="-1"><a class="header-anchor" href="#_5-디버깅-하기" aria-hidden="true">#</a> 5. 디버깅 하기</h3><p><code>launch.json</code>까지 설정했다면 디버그를 실행할 수 있습니다.<br> 터미널에서 <code>npm run start:debug</code>로 디버그 모드를 실행합니다.<br> 그다음 실행 및 디버그에서 &#39;디버그: 프로그램 시작&#39; 옆의 플레이 버튼을 눌러줍니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/cce43faa-86e3-430f-a664-e2e7859c738f" alt="Debbuger attached가 되면 디버깅이 가능합니다." tabindex="0" loading="lazy"><figcaption>Debbuger attached가 되면 디버깅이 가능합니다.</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/a36031b7-6489-4b55-8ee6-e0f1307857f1" alt="브레이크 포인트를 찍고 디버깅이 가능해집니다." tabindex="0" loading="lazy"><figcaption>브레이크 포인트를 찍고 디버깅이 가능해집니다.</figcaption></figure><h3 id="_6-컨테이너와-원격-연결-종료하기" tabindex="-1"><a class="header-anchor" href="#_6-컨테이너와-원격-연결-종료하기" aria-hidden="true">#</a> 6. 컨테이너와 원격 연결 종료하기</h3><p>원격 연결을 종료하는 방법은 두 가지 방법이 있는 것을 확인했습니다.</p><h4 id="_1-왼쪽-아래-원격-컨테이너를-누르고-vscode-명령팔레트에서-원격-연결-닫기로-나가기" tabindex="-1"><a class="header-anchor" href="#_1-왼쪽-아래-원격-컨테이너를-누르고-vscode-명령팔레트에서-원격-연결-닫기로-나가기" aria-hidden="true">#</a> 1. 왼쪽 아래 원격 컨테이너를 누르고 vscode 명령팔레트에서 원격 연결 닫기로 나가기</h4><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/5588f9b5-746d-4158-8b52-ae8520fc32ca" alt="왼쪽 아래 원격 컨테이너 누르기" tabindex="0" loading="lazy"><figcaption>왼쪽 아래 원격 컨테이너 누르기</figcaption></figure><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/d1efc0ac-7ba0-4a82-811b-3c392a681349" alt="원격 연결 닫기 선택" tabindex="0" loading="lazy"><figcaption>원격 연결 닫기 선택</figcaption></figure><h4 id="_2-원격-탐색기에서-원격-연결-종료시키기" tabindex="-1"><a class="header-anchor" href="#_2-원격-탐색기에서-원격-연결-종료시키기" aria-hidden="true">#</a> 2. 원격 탐색기에서 원격 연결 종료시키기</h4><p>왼쪽 사이드바에서 원격 탐색기를 선택하고 해당 컨테이너에서 원격 연결을 시작하거나 실행 중인 컨테이너를 종료할 수 있습니다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/968baff4-4709-4162-b5a1-76ea85b671c9" alt="연결 설정 혹은 종료" tabindex="0" loading="lazy"><figcaption>연결 설정 혹은 종료</figcaption></figure><h2 id="마무리" tabindex="-1"><a class="header-anchor" href="#마무리" aria-hidden="true">#</a> 마무리</h2><p>컨테이너를 시작할 때 마다 <code>docker compose up</code>을 해야하는 과정마저 줄어들고,<br> 리눅스 터미널을 사용해서 디버깅을 해볼 수 있다는 점에서 매력적이였습니다.<br> 같은 팀에서 리눅스를 OS로 쓰시는분이 계시는데 <code>docker compose up</code>으로 도커 환경과 연결할 때 DB가 연결되지 않는 현상이 있었습니다.<br> 그래서 로컬환경에서도 디버깅을 해보고, 도커 이미지 내의 리눅스 환경에서도 디버깅 해볼 수 있게 번경했습니다.</p>`,40);function k(g,h){const s=i("ExternalLinkIcon");return c(),p("div",null,[r,n("blockquote",null,[n("p",null,[n("a",d,[a("VS Code로 컨테이너 안에서 개발하기"),e(s)])]),n("p",null,[n("a",u,[a("Developing inside a Container - vscode 문서"),e(s)])])]),m,n("blockquote",null,[n("p",null,[n("a",v,[a("DevContainer 만들기 - vscode 문서"),e(s)])])]),b])}const _=o(l,[["render",k],["__file","dev-container.html.vue"]]);export{_ as default};
